139→// ---------------------------------------------------------------------------
140→// Data access helpers
141→// ---------------------------------------------------------------------------
142→
143→export function ensureDict(value: unknown): Record<string, unknown> {
144→  if (value !== null && typeof value === 'object' && !Array.isArray(value)) {
145→    return value as Record<string, unknown>
146→  }
147→  return {}
148→}
149→
150→export function ensureList(value: unknown): unknown[] {
151→  return Array.isArray(value) ? value : []
152→}
153→
154→export function getNested(payload: Record<string, unknown>, ...keys: string[]): unknown {
155→  let current: unknown = payload
156→  for (const key of keys) {
157→    if (current === null || typeof current !== 'object' || Array.isArray(current)) {
158→      return null
159→    }
160→    current = (current as Record<string, unknown>)[key]
161→  }
162→  return current ?? null
163→}
164→
165→export function loadJsonl(filePath: string): Record<string, unknown>[] {
166→  let content: string
167→  try {
168→    content = readFileSync(filePath, 'utf-8')
169→  } catch {
170→    return []
171→  }
172→  const records: Record<string, unknown>[] = []
173→  for (const line of content.split('\n')) {
174→    const trimmed = line.trim()
175→    if (!trimmed) continue
176→    try {
177→      records.push(JSON.parse(trimmed) as Record<string, unknown>)
178→    } catch {
179→      continue
180→    }
181→  }
182→  return records
183→}
184→
185→export function loadJson(filePath: string): Record<string, unknown> | null {
186→  if (!existsSync(filePath)) return null
187→  try {
188→    const text = readFileSync(filePath, 'utf-8')
189→    return JSON.parse(text) as Record<string, unknown>
190→  } catch {
191→    return null
192→  }
193→}
