195→// ---------------------------------------------------------------------------
196→// Text extraction helpers
197→// ---------------------------------------------------------------------------
198→
199→export function extractTextBlocks(blocks: unknown): string {
200→  const parts: string[] = []
201→
202→  for (const block of ensureList(blocks)) {
203→    if (typeof block === 'string') {
204→      const text = block.trim()
205→      if (text) parts.push(text)
206→      continue
207→    }
208→    if (block === null || typeof block !== 'object' || Array.isArray(block)) continue
209→
210→    const rec = block as Record<string, unknown>
211→    const blockType = String(rec['type'] ?? '').toLowerCase()
212→    if (ALL_SKIP_TYPES.has(blockType)) continue
213→    if (TEXT_BLOCK_TYPES.has(blockType)) {
214→      const text = String(rec['text'] ?? '').trim()
215→      if (text) parts.push(text)
216→      continue
217→    }
218→    const fallbackText = extractSimpleText(block)
219→    if (fallbackText) parts.push(fallbackText)
220→  }
221→  return joinParagraphs(parts)
222→}
223→
224→export function extractSimpleText(value: unknown): string {
225→  if (typeof value === 'string') return value.trim()
226→  if (Array.isArray(value)) {
227→    return joinParagraphs(value.map(item => extractSimpleText(item)))
228→  }
229→  if (value !== null && typeof value === 'object') {
230→    const rec = value as Record<string, unknown>
231→    for (const key of ['text', 'content', 'value']) {
232→      if (key in rec && typeof rec[key] === 'string') {
233→        return (rec[key] as string).trim()
234→      }
235→    }
236→    return ''
237→  }
238→  return ''
239→}
240→
241→export function extractGeminiText(node: Record<string, unknown>): string {
242→  const parts: string[] = []
243→  for (const key of ['parts', 'content', 'text', 'message']) {
244→    parts.push(...extractGeminiParts(node[key]))
245→  }
246→  return joinParagraphs(parts)
247→}
248→
249→export function extractGeminiParts(value: unknown): string[] {
250→  if (typeof value === 'string') {
251→    const text = value.trim()
252→    return text ? [text] : []
253→  }
254→  if (Array.isArray(value)) {
255→    const parts: string[] = []
256→    for (const item of value) {
257→      parts.push(...extractGeminiParts(item))
258→    }
259→    return parts
260→  }
261→  if (value !== null && typeof value === 'object') {
262→    const rec = value as Record<string, unknown>
263→    const blockType = String(rec['type'] ?? '').toLowerCase()
264→    if (ALL_SKIP_TYPES.has(blockType)) return []
265→    if ('text' in rec && typeof rec['text'] === 'string') {
266→      const text = (rec['text'] as string).trim()
267→      return text ? [text] : []
268→    }
269→    const parts: string[] = []
270→    for (const key of ['parts', 'content']) {
271→      if (key in rec) {
272→        parts.push(...extractGeminiParts(rec[key]))
273→      }
274→    }
275→    return parts
276→  }
277→  return []
278→}
279→
280→export function findFirstMappingWithKeys(value: unknown, keys: ReadonlySet<string>): Record<string, unknown> | null {
281→  if (value !== null && typeof value === 'object' && !Array.isArray(value)) {
282→    const rec = value as Record<string, unknown>
283→    const recKeys = Object.keys(rec)
284→    if (recKeys.some(k => keys.has(k))) return rec
285→    for (const v of Object.values(rec)) {
286→      const result = findFirstMappingWithKeys(v, keys)
287→      if (result !== null) return result
288→    }
289→    return null
290→  }
291→  if (Array.isArray(value)) {
292→    for (const item of value) {
293→      const result = findFirstMappingWithKeys(item, keys)
294→      if (result !== null) return result
295→    }
296→  }
297→  return null
298→}
