300→// ---------------------------------------------------------------------------
301→// Deduplication helpers
302→// ---------------------------------------------------------------------------
303→
304→export function deduplicateMessages(messages: readonly TranscriptMessage[]): TranscriptMessage[] {
305→  const seen = new Set<string>()
306→  const result: TranscriptMessage[] = []
307→  for (const msg of messages) {
308→    const sig = `${msg.timestamp ?? ''}\0${msg.role}\0${contentHash(msg.text)}`
309→    if (!seen.has(sig)) {
310→      seen.add(sig)
311→      result.push(msg)
312→    }
313→  }
314→  return result
315→}
316→
317→export function deduplicateToolEvents(events: readonly TranscriptToolEvent[]): TranscriptToolEvent[] {
318→  const seen = new Set<string>()
319→  const result: TranscriptToolEvent[] = []
320→  for (const evt of events) {
321→    const sig = `${evt.timestamp ?? ''}\0${contentHash(evt.summary)}`
322→    if (!seen.has(sig)) {
323→      seen.add(sig)
324→      result.push(evt)
325→    }
326→  }
327→  return result
328→}
329→
330→// ---------------------------------------------------------------------------
331→// Internal helpers
332→// ---------------------------------------------------------------------------
333→
334→function sortKeysDeep(value: unknown): unknown {
335→  if (Array.isArray(value)) return value.map(sortKeysDeep)
336→  if (value !== null && typeof value === 'object') {
337→    const sorted: Record<string, unknown> = {}
338→    for (const key of Object.keys(value as Record<string, unknown>).sort()) {
339→      sorted[key] = sortKeysDeep((value as Record<string, unknown>)[key])
340→    }
341→    return sorted
342→  }
343→  return value
344→}
345→
346→function formatUtcIso(d: Date): string {
347→  const year = d.getUTCFullYear()
348→  const month = String(d.getUTCMonth() + 1).padStart(2, '0')
349→  const day = String(d.getUTCDate()).padStart(2, '0')
350→  const hours = String(d.getUTCHours()).padStart(2, '0')
351→  const minutes = String(d.getUTCMinutes()).padStart(2, '0')
352→  const seconds = String(d.getUTCSeconds()).padStart(2, '0')
353→  return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}Z`
354→}
