 4→
 5→import {
 6→  appendFileSync,
 7→  copyFileSync,
 8→  existsSync,
 9→  mkdirSync,
10→  readFileSync,
11→  writeFileSync,
12→} from 'node:fs'
13→import { dirname } from 'node:path'
14→import type { StorageAdapter } from './adapter.js'
15→
16→export class LocalAdapter implements StorageAdapter {
17→  async writeFile(path: string, content: string | Buffer): Promise<void> {
18→    mkdirSync(dirname(path), { recursive: true })
19→    writeFileSync(path, content, typeof content === 'string' ? 'utf-8' : undefined)
20→  }
21→
22→  async readFile(path: string): Promise<string> {
23→    return readFileSync(path, 'utf-8')
24→  }
25→
26→  async exists(path: string): Promise<boolean> {
27→    return existsSync(path)
28→  }
29→
30→  async mkdir(path: string): Promise<void> {
31→    mkdirSync(path, { recursive: true })
32→  }
33→
34→  async copyFile(source: string, destination: string): Promise<void> {
35→    if (source === destination) return
36→    mkdirSync(dirname(destination), { recursive: true })
37→    copyFileSync(source, destination)
38→  }
39→
40→  async appendFile(path: string, content: string): Promise<void> {
41→    mkdirSync(dirname(path), { recursive: true })
42→    appendFileSync(path, content, 'utf-8')
43→  }
44→}
